     1→"use client";
     2→
     3→import {
     4→  createContext,
     5→  useContext,
     6→  useState,
     7→  useEffect,
     8→  useCallback,
     9→  type ReactNode,
    10→} from "react";
    11→import en from "./messages/en.json";
    12→import zh from "./messages/zh.json";
    13→
    14→const messages: Record<string, Record<string, string>> = { en, zh };
    15→
    16→type Locale = "en" | "zh";
    17→
    18→interface I18nContextValue {
    19→  locale: Locale;
    20→  setLocale: (locale: Locale) => void;
    21→  t: (key: string) => string;
    22→}
    23→
    24→const I18nContext = createContext<I18nContextValue | null>(null);
    25→
    26→const STORAGE_KEY = "changelogue-locale";
    27→
    28→export function LanguageProvider({ children }: { children: ReactNode }) {
    29→  const [locale, setLocaleState] = useState<Locale>("en");
    30→
    31→  // Read from localStorage on mount
    32→  useEffect(() => {
    33→    const stored = localStorage.getItem(STORAGE_KEY);
    34→    if (stored === "en" || stored === "zh") {
    35→      setLocaleState(stored);
    36→      document.documentElement.lang = stored;
    37→    }
    38→  }, []);
    39→
    40→  const setLocale = useCallback((next: Locale) => {
    41→    setLocaleState(next);
    42→    localStorage.setItem(STORAGE_KEY, next);
    43→    document.documentElement.lang = next;
    44→  }, []);
    45→
    46→  const t = useCallback(
    47→    (key: string): string => {
    48→      return messages[locale]?.[key] ?? messages.en?.[key] ?? key;
    49→    },
    50→    [locale]
    51→  );
    52→
    53→  return (
    54→    <I18nContext.Provider value={{ locale, setLocale, t }}>
    55→      {children}
    56→    </I18nContext.Provider>
    57→  );
    58→}
    59→
    60→export function useTranslation() {
    61→  const ctx = useContext(I18nContext);
    62→  if (!ctx) throw new Error("useTranslation must be used within LanguageProvider");
    63→  return ctx;
    64→}
