@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";
@import "@fontsource/jetbrains-mono/400.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: #dc2626;
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  /* Design-system extensions */
  --color-sidebar: var(--sidebar-bg);
  --color-sidebar-text: var(--sidebar-text);
  --color-beacon-accent: var(--beacon-accent);
  --color-mono-bg: var(--mono-bg);
  --color-text-secondary: var(--text-secondary);
  --color-text-muted: var(--text-muted);
  --color-surface: var(--surface);
}

:root {
  --radius: 0.375rem; /* 6px */

  /* Core layout colors */
  --background: #fafaf9;
  --foreground: #111113;
  --surface: #ffffff;
  --sidebar-bg: #16181c;
  --sidebar-text: #9ca3af;
  --beacon-accent: #e8601a;
  --border: #e8e8e5;
  --mono-bg: #f3f3f1;
  --text-secondary: #6b7280;
  --text-muted: #9ca3af;

  /* shadcn variable mappings */
  --popover: #ffffff;
  --popover-foreground: #111113;
  --card: #ffffff;
  --card-foreground: #111113;
  --primary: #e8601a;
  --primary-foreground: #ffffff;
  --secondary: #f3f3f1;
  --secondary-foreground: #374151;
  --muted: #f3f3f1;
  --muted-foreground: #6b7280;
  --accent: #f3f3f1;
  --accent-foreground: #111113;
  --input: #e8e8e5;
  --ring: #e8601a;

  /* Status colors */
  --status-completed: #16a34a;
  --status-running: #2563eb;
  --status-pending: #d97706;
  --status-failed: #dc2626;
}

html.dark {
  --background: #0f1115;
  --foreground: #e5e7eb;
  --surface: #16181c;
  --sidebar-bg: #0a0b0e;
  --sidebar-text: #6b7280;
  --beacon-accent: #e8601a;
  --border: #2a2d33;
  --mono-bg: #1e2025;
  --text-secondary: #9ca3af;
  --text-muted: #6b7280;

  /* shadcn variable mappings */
  --popover: #16181c;
  --popover-foreground: #e5e7eb;
  --card: #16181c;
  --card-foreground: #e5e7eb;
  --primary: #e8601a;
  --primary-foreground: #ffffff;
  --secondary: #1e2025;
  --secondary-foreground: #d1d5db;
  --muted: #1e2025;
  --muted-foreground: #9ca3af;
  --accent: #1e2025;
  --accent-foreground: #e5e7eb;
  --input: #2a2d33;
  --ring: #e8601a;
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
    font-family: var(--font-dm-sans), system-ui, sans-serif;
  }
}

/* Motion primitives */
@layer utilities {
  .fade-in {
    animation: fadeIn 150ms ease both;
  }
  @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
  }
}

/* Release notes rendered HTML */
.release-notes-content h1,
.release-notes-content h2,
.release-notes-content h3 {
  font-weight: 600;
  color: #111113;
  margin-top: 1.25em;
  margin-bottom: 0.5em;
}
.release-notes-content h1 { font-size: 1.25em; }
.release-notes-content h2 { font-size: 1.1em; }
.release-notes-content h3 { font-size: 1em; }
.release-notes-content p {
  margin-bottom: 0.75em;
}
.release-notes-content ul,
.release-notes-content ol {
  padding-left: 1.5em;
  margin-bottom: 0.75em;
}
.release-notes-content ul { list-style-type: disc; }
.release-notes-content ol { list-style-type: decimal; }
.release-notes-content li {
  margin-bottom: 0.25em;
}
.release-notes-content a {
  color: #2563eb;
  text-decoration: underline;
}
.release-notes-content a:hover {
  color: #1d4ed8;
}
.release-notes-content code {
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.9em;
  background: #f3f3f1;
  padding: 0.15em 0.35em;
  border-radius: 3px;
}
.release-notes-content pre {
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.9em;
  background: #f3f3f1;
  padding: 0.75em 1em;
  border-radius: 6px;
  overflow-x: auto;
  margin-bottom: 0.75em;
}
.release-notes-content pre code {
  background: none;
  padding: 0;
}
.release-notes-content blockquote {
  border-left: 3px solid #e8e8e5;
  padding-left: 1em;
  color: #6b7280;
  margin-bottom: 0.75em;
}
.release-notes-content img {
  max-width: 100%;
  height: auto;
}
.release-notes-content hr {
  border: none;
  border-top: 1px solid #e8e8e5;
  margin: 1em 0;
}
.release-notes-content table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 0.75em;
  font-size: 0.95em;
}
.release-notes-content th,
.release-notes-content td {
  border: 1px solid #e8e8e5;
  padding: 0.5em 0.75em;
  text-align: left;
}
.release-notes-content th {
  background: #fafaf9;
  font-weight: 600;
  color: #111113;
}
.release-notes-content tr:nth-child(even) {
  background: #fafaf9;
}
.release-notes-content > *:first-child {
  margin-top: 0;
}

