   469→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
   470→              style={{
   471→                backgroundColor: "#f3f3f1",
   472→                fontFamily: "'JetBrains Mono', monospace",
