   478→            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
   479→            {latestSr?.status === "completed" && (() => {
   480→              const pill = latestSr.report?.urgency
   481→                ? URGENCY_STYLES[latestSr.report.urgency.toLowerCase()]
