   539→            )}
   540→          </>
   541→        ) : (
   542→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   543→            {latestSr ? latestSr.status : "No analysis"}
   544→          </span>
   545→        )}
   546→      </span>
   547→
   548→      {/* Arrow */}
   549→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
