   554→/* ---------- Page ---------- */
   555→
   556→export default function ProjectsPage() {
   557→  const [createOpen, setCreateOpen] = useState(false);
   558→  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
   559→  const [search, setSearch] = useState("");
   560→  const [sortBy, setSortBy] = useState<"updated" | "added" | "name">("updated");
   561→  const [page, setPage] = useState(1);
   562→  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
   563→  const items = data?.data ?? [];
   564→
   565→  const PAGE_SIZE = 12;
   566→  const filtered = search
   567→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
   568→    : items;
   569→  const sorted = useMemo(() => {
   570→    const arr = [...filtered];
   571→    switch (sortBy) {
   572→      case "updated":
   573→        return arr.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
   574→      case "added":
   575→        return arr.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
   576→      case "name":
   577→        return arr.sort((a, b) => a.name.localeCompare(b.name));
   578→    }
   579→  }, [filtered, sortBy]);
   580→  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
   581→  const currentPage = Math.min(page, totalPages);
   582→  const paged = sorted.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
   583→
   584→  return (
   585→    <div className="flex flex-col gap-4 fade-in">
   586→      <div className="flex items-center justify-between">
   587→        <div>
   588→          <h1
   589→            style={{
   590→              fontFamily: "var(--font-fraunces)",
   591→              fontSize: "24px",
   592→              fontWeight: 700,
   593→              color: "#111113",
   594→            }}
   595→          >
   596→            Projects
   597→          </h1>
   598→          <p
   599→            className="mt-1 text-[13px] text-[#6b7280] inline-flex items-center gap-1"
   600→            style={{ fontFamily: "var(--font-dm-sans)" }}
   601→          >
   602→            Tracked projects, releases, and urgency at a glance.
   603→            <UrgencyLegend />
   604→          </p>
   605→        </div>
   606→        <div className="flex items-center gap-2">
   607→          <div className="relative">
   608→            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5" style={{ color: "#9ca3af" }} />
   609→            <input
   610→              type="text"
   611→              value={search}
   612→              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
   613→              placeholder="Search projects..."
   614→              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
   615→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   616→            />
   617→          </div>
   618→          <div className="flex items-center gap-1.5 rounded-md border px-2.5 py-1.5 text-[13px]" style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}>
   619→            <ArrowUpDown className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />
   620→            <select
   621→              value={sortBy}
   622→              onChange={(e) => { setSortBy(e.target.value as "updated" | "added" | "name"); setPage(1); }}
   623→              className="bg-transparent outline-none cursor-pointer text-[13px]"
   624→              style={{ fontFamily: "var(--font-dm-sans)", color: "#374151" }}
   625→            >
   626→              <option value="updated">Recently updated</option>
   627→              <option value="added">Recently added</option>
   628→              <option value="name">Name</option>
   629→            </select>
   630→          </div>
   631→          <div className="flex items-center rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   632→            <button
   633→              onClick={() => setViewMode("cards")}
   634→              className="p-1.5 rounded-l-md transition-colors"
   635→              style={{
   636→                backgroundColor: viewMode === "cards" ? "#f3f3f1" : "transparent",
   637→                color: viewMode === "cards" ? "#111113" : "#9ca3af",
   638→              }}
   639→              title="Card view"
   640→            >
   641→              <LayoutGrid className="h-4 w-4" />
   642→            </button>
   643→            <button
   644→              onClick={() => setViewMode("compact")}
   645→              className="p-1.5 rounded-r-md transition-colors"
   646→              style={{
   647→                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
   648→                color: viewMode === "compact" ? "#111113" : "#9ca3af",
   649→              }}
   650→              title="Compact view"
   651→            >
   652→              <List className="h-4 w-4" />
   653→            </button>
   654→          </div>
   655→          <button
   656→            onClick={() => setCreateOpen(true)}
   657→            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   658→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   659→          >
   660→            <Plus className="h-3.5 w-3.5" />
   661→            New Project
   662→          </button>
   663→        </div>
   664→      </div>
   665→
   666→      {isLoading ? (
   667→        <p
   668→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
