   673→      ) : items.length === 0 ? (
   674→        <div
   675→          className="flex flex-col items-center justify-center rounded-md border py-12"
   676→          style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   677→        >
   678→          <p
   679→            className="text-[14px] italic text-[#9ca3af]"
   680→            style={{ fontFamily: "var(--font-fraunces)" }}
   681→          >
   682→            No projects yet — create one to start tracking releases
   683→          </p>
   684→          <button
   685→            onClick={() => setCreateOpen(true)}
   686→            className="mt-4 flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
   687→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   688→          >
   689→            <Plus className="h-3.5 w-3.5" />
   690→            New Project
   691→          </button>
   692→        </div>
   693→      ) : filtered.length === 0 ? (
   694→        <p
   695→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
   696→          style={{ fontFamily: "var(--font-fraunces)" }}
   697→        >
