   739→
   740→      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
   741→        <DialogContent className="sm:max-w-lg">
   742→          <DialogHeader>
   743→            <DialogTitle>Create Project</DialogTitle>
   744→          </DialogHeader>
   745→          <ProjectForm
   746→            title="Create Project"
   747→            onSubmit={async (result) => {
   748→              const created = await projectsApi.create(result.project);
   749→              if (result.source && created.data?.id) {
   750→                const res = await sourcesApi.create(created.data.id, result.source);
   751→                if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   752→              }
