    23→  LOW: { bg: "#dcfce7", text: "#166534" },
    24→  MEDIUM: { bg: "#fef9c3", text: "#854d0e" },
    25→  HIGH: { bg: "#fee2e2", text: "#991b1b" },
    26→  CRITICAL: { bg: "#1f2937", text: "#ffffff" },
    27→};
    28→
    29→/* ------------------------------------------------------------------ */
    30→/*  Page                                                               */
    31→/* ------------------------------------------------------------------ */
    32→
    33→export default function TodoPage() {
    34→  return (
    35→    <Suspense>
    36→      <TodoPageInner />
    37→    </Suspense>
    38→  );
    39→}
    40→
    41→function TodoPageInner() {
    42→  const [activeTab, setActiveTab] = useState<StatusTab>("pending");
    43→  const [page, setPage] = useState(1);
    44→  const [aggregated, setAggregated] = useState(true);
    45→  const [confirmDialog, setConfirmDialog] = useState<{
    46→    action: string;
    47→    projectName?: string;
    48→    version?: string;
    49→    onConfirm: () => void;
    50→  } | null>(null);
    51→
    52→  /* Fetch todos for active tab */
    53→  const { data, isLoading, mutate } = useSWR(
    54→    ["todos", activeTab, page, aggregated],
    55→    () => todosApi.list(activeTab, page, PER_PAGE, aggregated)
    56→  );
    57→
    58→  /* Fetch counts for all three tabs */
    59→  const { data: pendingData, mutate: mutatePending } = useSWR(
    60→    ["todos-count", "pending", aggregated],
    61→    () => todosApi.list("pending", 1, 1, aggregated)
    62→  );
    63→  const { data: ackedData, mutate: mutateAcked } = useSWR(
    64→    ["todos-count", "acknowledged", aggregated],
    65→    () => todosApi.list("acknowledged", 1, 1, aggregated)
    66→  );
    67→  const { data: resolvedData, mutate: mutateResolved } = useSWR(
    68→    ["todos-count", "resolved", aggregated],
    69→    () => todosApi.list("resolved", 1, 1, aggregated)
    70→  );
    71→
    72→  const counts: Record<StatusTab, number> = {
    73→    pending: pendingData?.meta?.total ?? 0,
    74→    acknowledged: ackedData?.meta?.total ?? 0,
    75→    resolved: resolvedData?.meta?.total ?? 0,
    76→  };
    77→
    78→  /* SSE revalidation */
    79→  const revalidateAll = useCallback(() => {
    80→    mutate();
    81→    mutatePending();
    82→    mutateAcked();
    83→    mutateResolved();
    84→  }, [mutate, mutatePending, mutateAcked, mutateResolved]);
    85→
    86→  useEffect(() => {
    87→    const baseUrl = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    88→    const es = new EventSource(`${baseUrl}/events`);
    89→    es.onmessage = () => revalidateAll();
    90→    es.onerror = () => {
    91→      /* EventSource auto-reconnects; nothing to do */
    92→    };
    93→    return () => es.close();
    94→  }, [revalidateAll]);
    95→
    96→  const items: Todo[] = data?.data ?? [];
    97→  const total = data?.meta?.total ?? 0;
    98→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    99→  const startRow = (page - 1) * PER_PAGE + 1;
   100→  const endRow = Math.min(page * PER_PAGE, total);
   101→
   102→  /* Action handlers with optimistic updates */
   103→  const handleAcknowledge = async (id: string) => {
   104→    /* Optimistic: remove from current list */
   105→    mutate(
   106→      (prev) => {
   107→        if (!prev) return prev;
   108→        return {
   109→          ...prev,
   110→          data: prev.data.filter((t) => t.id !== id),
   111→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
   112→        };
   113→      },
   114→      { revalidate: false }
   115→    );
   116→    try {
   117→      await todosApi.acknowledge(id, true);
   118→    } catch {
   119→      /* Revert on failure */
   120→    }
   121→    revalidateAll();
   122→  };
   123→
   124→  const handleResolve = async (id: string, cascade = true) => {
   125→    mutate(
   126→      (prev) => {
   127→        if (!prev) return prev;
   128→        return {
   129→          ...prev,
   130→          data: prev.data.filter((t) => t.id !== id),
   131→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
   132→        };
   133→      },
   134→      { revalidate: false }
   135→    );
   136→    try {
   137→      await todosApi.resolve(id, cascade);
   138→    } catch {
   139→      /* Revert on failure */
   140→    }
   141→    revalidateAll();
   142→  };
   143→
   144→  const handleReopen = async (id: string) => {
   145→    mutate(
   146→      (prev) => {
   147→        if (!prev) return prev;
   148→        return {
   149→          ...prev,
   150→          data: prev.data.filter((t) => t.id !== id),
   151→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
   152→        };
   153→      },
   154→      { revalidate: false }
   155→    );
   156→    try {
   157→      await todosApi.reopen(id);
   158→    } catch {
   159→      /* Revert on failure */
   160→    }
   161→    revalidateAll();
   162→  };
