   206→                    backgroundColor: isActive ? "#e8e8e5" : "#f3f3f1",
   207→                    color: isActive ? "#111113" : "#9ca3af",
   208→                  }}
   209→                >
   210→                  {counts[tab.key]}
   211→                </span>
   212→              </button>
   213→            );
   214→          })}
