   221→          }}
   222→          className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors"
   223→          style={{
   224→            fontFamily: "var(--font-dm-sans)",
   225→            fontSize: "13px",
   226→            fontWeight: 500,
   227→            color: aggregated ? "#111113" : "#6b7280",
   228→            backgroundColor: aggregated ? "#f3f3f1" : "transparent",
   229→            border: aggregated ? "1px solid #e8e8e5" : "1px solid transparent",
   230→          }}
