    32→/* ---------- Overflow Flow ---------- */
    33→
    34→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    35→const MAX_LINES = 2;
    36→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    37→
    38→function FlowSection({
    39→  label,
    40→  moreHref,
    41→  children,
    42→}: {
    43→  label: string;
    44→  moreHref: string;
    45→  children: React.ReactNode;
    46→}) {
    47→  const measureRef = useRef<HTMLDivElement>(null);
    48→  const moreRef = useRef<HTMLSpanElement>(null);
    49→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    50→
    51→  const items = React.Children.toArray(children);
    52→
    53→  const measure = useCallback(() => {
    54→    const el = measureRef.current;
    55→    if (!el) return;
    56→    const nodes = el.children;
    57→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    58→    // Check if everything fits without overflow
    59→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    60→      setVisibleCount(items.length);
    61→      return;
    62→    }
    63→    // Measure actual "more…" link width
    64→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    65→    const containerWidth = el.offsetWidth;
    66→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    67→    let lastFitting = 0;
    68→    for (let i = 1; i <= itemNodeCount; i++) {
    69→      const node = nodes[i] as HTMLElement;
    70→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    71→      lastFitting = i;
    72→    }
    73→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    74→    let count = lastFitting;
    75→    while (count > 1) {
    76→      const node = nodes[count] as HTMLElement;
    77→      const nodeBottom = node.offsetTop + node.offsetHeight;
    78→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    79→      if (nodeBottom <= LINE_HEIGHT) break;
    80→      // Item is on line 2 — check if "more…" fits after it on the same line
    81→      const nodeRight = node.offsetLeft + node.offsetWidth;
    82→      if (nodeRight + moreWidth <= containerWidth) break;
    83→      count--;
    84→    }
    85→    setVisibleCount(Math.max(1, count));
    86→  }, [items.length]);
    87→
    88→  useEffect(() => {
    89→    const raf = requestAnimationFrame(measure);
    90→    const obs = new ResizeObserver(measure);
    91→    if (measureRef.current) obs.observe(measureRef.current);
    92→    return () => {
    93→      cancelAnimationFrame(raf);
    94→      obs.disconnect();
    95→    };
    96→  }, [measure, items.length]);
    97→
    98→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
    99→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   100→
