     1→"use client";
     2→
     3→import { useState } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Button } from "@/components/ui/button";
     6→import { Input } from "@/components/ui/input";
     7→import { Label } from "@/components/ui/label";
     8→import { Textarea } from "@/components/ui/textarea";
     9→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    10→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    11→import type { Project, ProjectInput, SourceInput } from "@/lib/api/types";
    12→import { validateRepository } from "@/lib/format";
    13→import { Plus, X } from "lucide-react";
    14→
    15→export interface ProjectFormResult {
    16→  project: ProjectInput;
    17→  source?: SourceInput;
    18→}
    19→
    20→interface ProjectFormProps {
    21→  initial?: Project;
    22→  onSubmit: (result: ProjectFormResult) => Promise<void>;
    23→  title: string;
    24→  /** Hide the source section (used in edit mode) */
    25→  hideSource?: boolean;
    26→  /** Dialog mode: called after successful submit instead of router.push */
    27→  onSuccess?: () => void;
    28→  /** Dialog mode: called on cancel instead of router.back */
    29→  onCancel?: () => void;
    30→}
    31→
    32→export function ProjectForm({ initial, onSubmit, title, hideSource, onSuccess, onCancel }: ProjectFormProps) {
    33→  const router = useRouter();
    34→  const [saving, setSaving] = useState(false);
    35→  const [name, setName] = useState(initial?.name ?? "");
    36→  const [description, setDescription] = useState(initial?.description ?? "");
    37→  const [error, setError] = useState("");
    38→
    39→  /* Source fields (only for create) */
    40→  const [showSource, setShowSource] = useState(false);
    41→  const [provider, setProvider] = useState("github");
    42→  const [repository, setRepository] = useState("");
    43→  const [pollInterval, setPollInterval] = useState("86400");
    44→  const [versionFilterInclude, setVersionFilterInclude] = useState("");
    45→  const [versionFilterExclude, setVersionFilterExclude] = useState("");
    46→  const [excludePrereleases, setExcludePrereleases] = useState(false);
    47→
    48→  const handleCancel = () => {
    49→    if (onCancel) {
    50→      onCancel();
    51→    } else {
    52→      router.back();
    53→    }
    54→  };
    55→
    56→  const handleSubmit = async (e: React.FormEvent) => {
    57→    e.preventDefault();
    58→    setError("");
    59→    setSaving(true);
    60→    try {
    61→      const result: ProjectFormResult = {
    62→        project: {
    63→          name,
    64→          description: description || undefined,
    65→        },
    66→      };
    67→      if (showSource && repository.trim()) {
    68→        const repoError = validateRepository(provider, repository.trim());
    69→        if (repoError) {
    70→          setError(repoError);
    71→          setSaving(false);
    72→          return;
    73→        }
    74→        result.source = {
    75→          provider,
    76→          repository: repository.trim(),
    77→          poll_interval_seconds: Number(pollInterval) || 86400,
    78→          enabled: true,
    79→          version_filter_include: versionFilterInclude.trim() || undefined,
    80→          version_filter_exclude: versionFilterExclude.trim() || undefined,
    81→          exclude_prereleases: excludePrereleases || undefined,
    82→        };
    83→      }
    84→      await onSubmit(result);
    85→      if (onSuccess) {
    86→        onSuccess();
    87→      } else {
    88→        router.push("/projects");
    89→      }
    90→    } catch (err: unknown) {
    91→      setError(err instanceof Error ? err.message : "Failed to save");
    92→    } finally {
    93→      setSaving(false);
    94→    }
    95→  };
    96→
    97→  const formContent = (
    98→    <form onSubmit={handleSubmit} className="space-y-4">
    99→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
   100→      <div className="space-y-2">
   101→        <Label htmlFor="name">Name</Label>
   102→        <Input id="name" value={name} onChange={(e) => setName(e.target.value)} required />
   103→      </div>
   104→      <div className="space-y-2">
   105→        <Label htmlFor="description">Description</Label>
   106→        <Textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows={2} />
   107→      </div>
   108→
   109→      {/* Optional source section — only in create mode */}
   110→      {!hideSource && (
   111→        <div className="space-y-3">
   112→          {!showSource ? (
   113→            <button
   114→              type="button"
   115→              onClick={() => setShowSource(true)}
   116→              className="inline-flex items-center gap-1.5 text-[13px] font-medium transition-colors hover:opacity-80"
   117→              style={{ color: "var(--beacon-accent)" }}
   118→            >
   119→              <Plus className="h-3.5 w-3.5" />
   120→              Add a Source
   121→            </button>
   122→          ) : (
   123→            <div className="rounded-md border p-4 space-y-3" style={{ borderColor: "var(--border)" }}>
   124→              <div className="flex items-center justify-between">
   125→                <Label className="text-[13px] font-medium">Add a Source</Label>
   126→                <button
   127→                  type="button"
   128→                  onClick={() => { setShowSource(false); setRepository(""); }}
   129→                  className="text-text-muted hover:text-text-secondary"
   130→                >
   131→                  <X className="h-4 w-4" />
   132→                </button>
   133→              </div>
   134→              <div className="space-y-2">
   135→                <Label>Provider</Label>
   136→                <Select value={provider} onValueChange={setProvider}>
   137→                  <SelectTrigger><SelectValue /></SelectTrigger>
   138→                  <SelectContent>
   139→                    <SelectItem value="github">GitHub</SelectItem>
