    14→
    15→interface SourceFormProps {
    16→  initial?: Source;
    17→  projectId?: string;
    18→  onSubmit: (input: SourceInput) => Promise<void>;
    19→  title: string;
    20→  redirectTo?: string;
    21→  onSuccess?: () => void;
    22→  onCancel?: () => void;
    23→}
    24→
    25→
    26→const POLL_INTERVAL_OPTIONS = [
    27→    { label: "Hourly", value: "3600" },
    28→    { label: "Daily", value: "86400" },
    29→    { label: "Weekly", value: "604800" },
    30→    { label: "Monthly", value: "2592000" },
    31→  ];
    32→
    33→  function nearestPollInterval(seconds: number): string {
    34→    const values = POLL_INTERVAL_OPTIONS.map((o) => Number(o.value));
    35→    let closest = values[0];
    36→    for (const v of values) {
    37→      if (Math.abs(v - seconds) < Math.abs(closest - seconds)) closest = v;
    38→    }
    39→    return String(closest);
    40→  }
    41→
    42→
    43→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    44→  const router = useRouter();
    45→  const [saving, setSaving] = useState(false);
    46→  const [error, setError] = useState("");
    47→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    48→  const [repository, setRepository] = useState(initial?.repository ?? "");
    49→  const [pollInterval, setPollInterval] = useState(
    50→    nearestPollInterval(initial?.poll_interval_seconds ?? 86400)
    51→  );
    52→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    53→  const [configJson, setConfigJson] = useState(
    54→    JSON.stringify(initial?.config ?? {}, null, 2)
    55→  );
    56→  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
    57→  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
    58→  const [excludePrereleases, setExcludePrereleases] = useState(initial?.exclude_prereleases ?? false);
    59→
    60→  const handleSubmit = async (e: React.FormEvent) => {
    61→    e.preventDefault();
    62→    setError("");
    63→
    64→    const repoError = validateRepository(provider, repository);
    65→    if (repoError) {
    66→      setError(repoError);
    67→      return;
    68→    }
    69→
    70→    let parsedConfig: Record<string, unknown> | undefined;
    71→    if (configJson.trim() && configJson.trim() !== "{}") {
    72→      try {
    73→        parsedConfig = JSON.parse(configJson);
    74→      } catch {
    75→        setError("Config must be valid JSON");
    76→        return;
    77→      }
    78→    }
    79→
    80→    setSaving(true);
    81→    try {
    82→      await onSubmit({
    83→        provider,
    84→        repository: repository.trim(),
    85→        poll_interval_seconds: Number(pollInterval),
    86→        enabled,
    87→        config: parsedConfig,
    88→        version_filter_include: versionFilterInclude.trim() || undefined,
    89→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    90→        exclude_prereleases: excludePrereleases || undefined,
    91→      });
    92→      if (onSuccess) {
    93→        onSuccess();
    94→      } else {
    95→        router.push(redirectTo ?? "/sources");
    96→      }
    97→    } catch (err: unknown) {
    98→      setError(err instanceof Error ? err.message : "Failed to save");
    99→    } finally {
   100→      setSaving(false);
   101→    }
   102→  };
   103→
   104→  const handleCancel = () => {
   105→    if (onCancel) {
   106→      onCancel();
   107→    } else {
   108→      router.back();
   109→    }
   110→  };
   111→
   112→  const formContent = (
   113→    <form onSubmit={handleSubmit} className="space-y-4">
   114→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
   115→      <div className="space-y-2">
   116→        <Label>Provider</Label>
   117→        <Select value={provider} onValueChange={setProvider}>
   118→          <SelectTrigger><SelectValue /></SelectTrigger>
   119→          <SelectContent>
   120→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
   121→            <SelectItem value="github">GitHub</SelectItem>
   122→            <SelectItem value="ecr-public">ECR Public</SelectItem>
   123→            <SelectItem value="gitlab">GitLab</SelectItem>
   124→            <SelectItem value="pypi">PyPI</SelectItem>
   125→            <SelectItem value="npm">npm</SelectItem>
   126→          </SelectContent>
   127→        </Select>
   128→      </div>
   129→      <div className="space-y-2">
   130→        <Label htmlFor="repository">Repository</Label>
   131→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   132→      </div>
   133→      <div className="space-y-2">
   134→        <Label>Poll Interval</Label>
   135→        <Select value={pollInterval} onValueChange={setPollInterval}>
   136→          <SelectTrigger><SelectValue /></SelectTrigger>
   137→          <SelectContent>
   138→            {POLL_INTERVAL_OPTIONS.map((opt) => (
   139→              <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>
   140→            ))}
   141→          </SelectContent>
   142→        </Select>
   143→      </div>
   144→      <div className="space-y-2">
   145→        <Label htmlFor="config">Config (JSON, optional)</Label>
   146→        <Textarea
   147→          id="config"
   148→          value={configJson}
   149→          onChange={(e) => setConfigJson(e.target.value)}
   150→          rows={4}
   151→          className="font-mono text-sm"
   152→          placeholder="{}"
   153→        />
   154→      </div>
   155→      <div className="space-y-2">
   156→        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   157→        <Input
   158→          id="version_filter_include"
   159→          value={versionFilterInclude}
   160→          onChange={(e) => setVersionFilterInclude(e.target.value)}
   161→          placeholder='e.g. ^v\d+\.\d+\.\d+$'
   162→          className="font-mono text-sm"
   163→        />
   164→        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   165→      </div>
   166→      <div className="space-y-2">
   167→        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   168→        <Input
   169→          id="version_filter_exclude"
   170→          value={versionFilterExclude}
   171→          onChange={(e) => setVersionFilterExclude(e.target.value)}
   172→          placeholder='e.g. -(alpha|beta|rc|nightly)'
   173→          className="font-mono text-sm"
   174→        />
   175→        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   176→      </div>
   177→      {(provider === "github" || provider === "gitlab" || provider === "pypi" || provider === "npm") && (
   178→        <div className="flex items-center gap-3">
   179→          <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
   180→          <Label>Exclude Pre-Releases</Label>
   181→        </div>
   182→      )}
   183→      <div className="flex items-center gap-3">
   184→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   185→        <Label>Enabled</Label>
   186→      </div>
   187→      <div className="flex justify-end gap-2">
   188→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   189→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   190→      </div>
   191→    </form>
   192→  );
   193→
   194→  if (onSuccess) {
   195→    return formContent;
   196→  }
   197→
   198→  return (
   199→    <Card className="mx-auto max-w-2xl">
   200→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   201→      <CardContent>
   202→        {formContent}
   203→      </CardContent>
   204→    </Card>
   205→  );
   206→}
